text = ""

# Kasiski's analysis
# Iterate through the program

bigrams = {}

for i in range(0,len(text)-1):
    if(text[i:i+2] in bigrams):
        bigrams[text[i:i+2]].append(i)
    else:
        bigrams[text[i:i+2]] = [i]

bigram_pos = sorted(bigrams.items(), key=lambda s: len(s[1]))

for item in bigram_pos:
    bigram = item[0]
    arr = item[1]
    new = [arr[0]]

    if(len(arr) > 1):
        for i in range(1,len(arr)):
            new.append(arr[i]-arr[i-1])
    
    # print(f'{bigram}', new[1:])

trigrams = {}

for i in range(0,len(text)-2):
    if(text[i:i+3] in trigrams):
        trigrams[text[i:i+3]].append(i)
    else:
        trigrams[text[i:i+3]] = [i]

trigram_pos = sorted(trigrams.items(), key=lambda s: len(s[1]))
trigram_muls = []

for item in trigram_pos:
    trigram = item[0]
    arr = item[1]
    new = [arr[0]]

    if(len(arr) > 1):
        for i in range(1,len(arr)):
            new.append(arr[i]-arr[i-1])
    
    print(f'{trigram}', new[1:])

